        void SetupExperiment()
        {
            Data = new ExperimentData("ExperimentDesignerData");

            Data.Instrument = Instrument;

            Data.CellVolume = Instrument.GetProperties().StandardCellVolume;
            Data.CellConcentration = CellConcentration;
            Data.SyringeConcentration = SyringeConcentration;

            int injcount = InjectionCount;
            double volume = GetInjectionVolume(injcount);

            var segments = new List<TandemConcatenation.TandemInjectionSegment>();

            for (int segment = 0; segment < TandemSegmentCount; segment++)
            {
                var segmentStart = Data.Injections.Count;

                for (int i = 0; i < injcount; i++)
                {
                    var injectionID = Data.Injections.Count;

                    if (i == 0 && UseSmallFirstInjection)
                    {
                        Data.Injections.Add(new InjectionData(Data, injectionID, SmallInjectionVolume, 0, false));
                    }
                    else Data.Injections.Add(new InjectionData(Data, injectionID, volume, 0, true));
                }

                if (UseTandemExperiment)
                    segments.Add(new TandemConcatenation.TandemInjectionSegment(segmentStart, injcount, $"Load {segment + 1}"));
            }

            if (UseTandemExperiment)
                TandemConcatenation.ProcessInjectionsWithBackMixing(Data, segments, CreateDesignerTandemBackMixingSettings());
            else
                RawDataReader.ProcessInjections(Data);

            SetInjectionDescription();

            ModelControl.Enabled = true;

            SetupModel();
        }

        private double GetInjectionVolume(int injcount)
        {
            if (UseAutoInjectionVolume)
                return CalculateAutomaticInjectionVolume(injcount);

            return GetManualInjectionVolumeMicroliters() * MicroliterToLiter;
        }

        private double CalculateAutomaticInjectionVolume(int injcount)
        {
            var volume = UseSmallFirstInjection ?
                (Instrument.GetProperties().StandardSyringeVolume - SmallInjectionVolume) / (injcount - 1) :
                Instrument.GetProperties().StandardSyringeVolume / injcount;

            return Math.Floor(volume * 10000000) / 10000000;
        }

        private void UpdateInjectionVolumeControls(int injcount)
        {
            var auto = UseAutoInjectionVolume;

            if (auto)
                SetInjectionVolumeControlValues(CalculateAutomaticInjectionVolume(injcount) * LiterToMicroliter);
            else
                SyncManualInjectionVolumeFromField();

            if (InjectionVolumeField != null)
                InjectionVolumeField.Enabled = !auto;
            if (InjectionVolumeStepper != null)
                InjectionVolumeStepper.Enabled = !auto;
        }

        private void SyncManualInjectionVolumeFromField()
        {
            if (InjectionVolumeField == null) return;

            SetInjectionVolumeControlValues(InjectionVolumeField.DoubleValue);
        }

        private double GetManualInjectionVolumeMicroliters()
        {
            return ValidateInjectionVolumeMicroliters(InjectionVolumeField?.DoubleValue ?? DefaultManualInjectionVolumeMicroliters);
        }

        private void SetInjectionVolumeControlValues(double volumeMicroliters)
        {
            var value = ValidateInjectionVolumeMicroliters(volumeMicroliters);

            if (InjectionVolumeField != null)
                InjectionVolumeField.DoubleValue = value;
            if (InjectionVolumeStepper != null)
                InjectionVolumeStepper.DoubleValue = value;
        }

        private double ValidateInjectionVolumeMicroliters(double volumeMicroliters)
        {
            var min = InjectionVolumeStepper?.MinValue ?? 0.1;
            var max = InjectionVolumeStepper?.MaxValue ?? 20.0;
            var value = volumeMicroliters > 0 ? volumeMicroliters : DefaultManualInjectionVolumeMicroliters;

            return Math.Min(Math.Max(value, min), max);
        }

        private TandemConcatenation.BackMixingSettings CreateDesignerTandemBackMixingSettings()
        {
            return new TandemConcatenation.BackMixingSettings
            {
                UseBackMixingMethod = true,
                DidRemoveOverflow = true,
                DeadVolume = Instrument.GetProperties().DeadVolume,
                MixingFraction = DesignerTandemMixingFraction,
                RemoveOverflowVolume = 0.0,
            };
        }

        private void SetInjectionDescription()
        {
            string injdescription = "";

            for (int i = 0; i < Data.Injections.Count; i++)
            {
                var curr = Data.Injections[i];
                var next = i < Data.InjectionCount - 1 ? Data.Injections[i + 1] : null;
                var prev = i > 0 ? Data.Injections[i - 1] : null;

                if (Data.Injections.Where(inj => inj.ID > i).All(inj => inj.Volume == curr.Volume))
                {
                    // All subsequent are identical, finish up
                    injdescription += "#" + (i + 1).ToString() + "-" + Data.Injections.Count.ToString() + ": " + (1000000 * curr.Volume).ToString("F1") + " µl, ";
                    break;
                }
                else if (next != null && curr.Volume == next.Volume)
                {
                    string row = $"#{i + 1}-";

                    while (i < Data.InjectionCount)
                    {
                        i++;

                        next = i < Data.InjectionCount - 1 ? Data.Injections[i + 1] : null;

                        if (next == null || curr.Volume != next.Volume) break;
                    }

                    row += $"{i + 1}: {1000000 * curr.Volume:F1} µl, ";

                    injdescription += row;
                }
                else if (next != null && curr.Volume != next.Volume)
                    injdescription += "#" + (i + 1).ToString() + ": " + (1000000 * curr.Volume).ToString("F1") + " µl, ";
                else if (prev != null && curr.Volume != prev.Volume)
                    injdescription += "#" + (i + 1).ToString() + ": " + (1000000 * curr.Volume).ToString("F1") + " µl, ";
            }

            injdescription = injdescription.Substring(0, injdescription.Length - 2);

            InjectionInfoField.StringValue = injdescription;
        }

        void SetupModel()
        {
            if (Data == null) return;
            Factory = new SingleModelFactory(Model);

            Factory.InitializeModel(Data);

            if (Factory == null) return;

            ClearStackView(ModelOptionsStackView);
            ClearStackView(ParameterStackView);

            ParameterValueAdjustmentView[] tmppars = new ParameterValueAdjustmentView[ParameterControls.Count];

            ParameterControls.CopyTo(tmppars);
            ParameterControls.Clear();

            foreach (var par in Factory.GetExposedParameters())
            {
                ParameterValueAdjustmentView sv;

                // Set some meaningful default value for enthalpy type variables
                if (par.Key.GetProperties().ParentType == ParameterType.Enthalpy1)
                    par.Update(-30000);
                if (par.Key.GetProperties().ParentType == ParameterType.Nvalue1) par.Update(1);

                if (tmppars.ToList().Exists(view => view.Key == par.Key))
                {
                    sv = tmppars.ToList().Find(view => view.Key == par.Key);
                }
                else
                {
                    sv = new ParameterValueAdjustmentView(
                        new CoreGraphics.CGRect(0, 0, ParameterStackView.Frame.Width, 20),
                        par,
                        AdjustmentViewMode.Designer);
                }
                sv.ValueChanged -= ParameterControl_ValueChanged;
                sv.ValueChanged += ParameterControl_ValueChanged;
                ParameterControls.Add(sv);

                ParameterStackView.AddArrangedSubview(sv);
            }

            foreach (var sv in OptionControls)
            {
                sv.ApplyOptions();
            }

            var tmpopts = OptionControls.ToArray();
            OptionControls.Clear();

            bool showoptions = Factory.Model.ModelOptions.Count > 0;
            ModelOptionsStackView.Hidden = !showoptions;
            ModelOptionsLine.Hidden = !showoptions;
            ModelOptionsLabel.Hidden = !showoptions;

            if (showoptions)
            {
                foreach (var opt in Factory.GetExposedModelOptions())
                {
                    var old = tmpopts.FirstOrDefault(v => v.Key == opt.Key);
                    if (old != null)
                    {
                        opt.Value.BoolValue = old.Option.BoolValue;
                        opt.Value.ParameterValue = old.Option.ParameterValue;
                        opt.Value.IntValue = old.Option.IntValue;
                        opt.Value.DoubleValue = old.Option.DoubleValue;
                        opt.Value.StringValue = old.Option.StringValue;
                    }

                    var sv = new OptionAdjustmentView(
                        new CoreGraphics.CGRect(0, 0, ModelOptionsStackView.Frame.Width, 20),
                        opt.Value,
                        AdjustmentViewMode.Designer);

                    sv.SetupDesignerLayout();
                    sv.ValueChanged -= OptionControl_ValueChanged;
                    sv.ValueChanged += OptionControl_ValueChanged;
                    OptionControls.Add(sv);
                    ModelOptionsStackView.AddArrangedSubview(sv);
                }
            }

            RefreshDesignerControlStates();

            if (AutoRunExperimentSimulation)
                UpdateSyntheticData();
        }

        private static void ClearStackView(NSStackView stack)
        {
            foreach (var view in stack.ArrangedSubviews.ToArray())
            {
                stack.RemoveArrangedSubview(view);
                view.RemoveFromSuperview();
            }
        }

