        private void OptionControl_ValueChanged(object sender, EventArgs e)
        {
            if (AutoRunExperimentSimulation)
                UpdateSyntheticData();
            else
                ApplyDesignerInputsToFactory();

            RefreshDesignerControlStates();
        }

        private void RefreshDesignerControlStates()
        {
            if (Factory == null) return;

            var attributes = Factory.GetExposedModelOptions();

            foreach (var sv in OptionControls)
                sv.UpdateState(attributes);

            foreach (var sv in ParameterControls)
                sv.UpdateState(attributes);
        }

        private void UpdateSyntheticData()
        {
            if (_isrunning || Factory == null) return;

            ApplyDesignerInputsToFactory();
            Factory.BuildModel();
            SimulateSyntheticData();
        }

        private void ApplyDesignerInputsToFactory()
        {
            if (Factory == null) return;

            foreach (var sv in ParameterControls)
            {
                Factory.UpdateParameter(sv.Key, sv.Value, false);
            }

            foreach (var sv in OptionControls)
            {
                sv.ApplyOptions();
            }
        }

        private void SimulateSyntheticData()
        {
            if (Data?.Model == null) return;

            Data.Model.Solution = SolutionInterface.FromModel(Data.Model, SolverConvergence.ReportStopped(DateTime.Now));

            foreach (var inj in Data.Injections)
            {
                var injmass = IsSmallInitialInjection(inj) ? inj.InjectionMass * 0.8 : inj.InjectionMass;
                var dH = Data.Model.EvaluateEnthalpy(inj.ID);
                var noise = SimulateNoiseControl.State == NSCellStateValue.On ?
                    2000 / (Math.Sqrt(inj.InjectionMass * Math.Pow(10, 11))) :
                    0;
                var heat = injmass * new FloatWithError(dH, noise).Sample();
                inj.SetPeakArea(new(heat));
            }

            SimGraphView.Initialize(Data);
        }

        private bool IsSmallInitialInjection(InjectionData injection)
        {
            if (!UseSmallFirstInjection) return false;

            if (Data?.Segments != null)
                return Data.Segments.Any(segment => segment.FirstInjectionID == injection.ID);

            return injection.ID == 0;
        }

        private void FitSyntheticData()
        {
            if (_isrunning || Factory == null || Data?.Model == null) return;

            var solver = Solver.Initialize(Factory);
            solver.CanCreateAnalysisResult = false;
            solver.SolverToleranceModifier = 2;
            solver.ErrorEstimationMethod = SimulateNoiseControl.State == NSCellStateValue.On ? ErrorEstimationMethod.BootstrapResiduals : ErrorEstimationMethod.None;
            solver.BootstrapIterations = 50;
            var mco = (solver as Solver).Model.ModelCloneOptions;
            mco.IncludeConcentrationErrorsInBootstrap = true;
            mco.EnableAutoConcentrationVariance = false;

            solver.Analyze();
        }
